const body = $input.first().json.body || $input.first().json;
try {
  const message = body.entry?.[0]?.changes?.[0]?.value?.messages?.[0];
  if (!message) return [];
  const from = message.from;
  const type = message.type;
  if (type === 'text') {
    return [{ json: { from, type, textContent: message.text?.body, audioId: null, audioMime: null } }];
  } else if (type === 'audio') {
    return [{ json: { from, type, textContent: null, audioId: message.audio?.id, audioMime: message.audio?.mime_type || 'audio/ogg' } }];
  } else {
    return [{ json: { from, type, textContent: `[Mensaje de tipo ${type} no soportado. Usá texto o audio.]`, audioId: null, audioMime: null } }];
  }
} catch (e) {
  return [];
}

const from = $('Parse Meta Payload').first().json.from;
const audioMime = $('Parse Meta Payload').first().json.audioMime || 'audio/ogg';
const binary = $input.first().binary?.data;
if (!binary) return [{ json: { from, userMessage: '[No pude descargar el audio]' } }];
const geminiBody = {
  contents: [{ role: 'user', parts: [
    { text: 'Transcribí este audio en español rioplatense y devolvé solo el texto transcripto, sin explicaciones:' },
    { inlineData: { mimeType: audioMime, data: binary.data } }
  ]}],
  generationConfig: { temperature: 0.1, maxOutputTokens: 300 }
};
return [{ json: { from, geminiBody } }];

const source = $input.first().json;
let from, userMessage;

if (source.candidates) {
  from = $('Preparar transcripción').first().json.from;
  userMessage = source.candidates?.[0]?.content?.parts?.[0]?.text?.trim() || '[Audio ininteligible]';
} else {
  from = source.from;
  userMessage = source.textContent || '';
}

return [{ json: { from, userMessage } }];

const from = $input.first().json.from;
const userMessage = $input.first().json.userMessage || '';
const msg = userMessage.toLowerCase();

const API_BASE = 'http://host.docker.internal:8080';
const headers = {
  'Accept': 'application/json',
  'X-User-Name': 'whatsapp-bot',
  'X-Bot-Token': 'sgo-bot-internal-token-2024'
};

async function get(path) {
  return await this.helpers.httpRequest({ method: 'GET', url: `${API_BASE}${path}`, headers, json: true, timeout: 15000 });
}

function findByName(items, term) {
  const lower = term.toLowerCase().trim();
  return items.find(i => (i.nombre || '').toLowerCase() === lower)
    || items.find(i => (i.nombre || '').toLowerCase().includes(lower))
    || null;
}

let contexto = '';

try {
  // Detectar si pregunta por saldo/cuenta corriente de nombre específico
  const saldoCliente = msg.match(/saldo.{0,20}cliente[:\s]+([a-záéíóúñ\s]+)/i) || msg.match(/cuenta.{0,20}cliente[:\s]+([a-záéíóúñ\s]+)/i);
  const saldoProveedor = msg.match(/saldo.{0,20}proveedor[:\s]+([a-záéíóúñ\s]+)/i) || msg.match(/cuenta.{0,20}proveedor[:\s]+([a-záéíóúñ\s]+)/i);
  const ccObra = msg.match(/cuenta.{0,20}obra[:\s]+([a-záéíóúñ\s]+)/i) || msg.match(/cc.{0,20}obra[:\s]+([a-záéíóúñ\s]+)/i);

  if (saldoCliente) {
    const nombre = saldoCliente[1].trim();
    const clientes = await get.call(this, '/api/clientes');
    const c = findByName(clientes, nombre);
    if (!c) {
      contexto = `No encontré cliente "${nombre}" en el sistema.`;
    } else {
      const saldo = await get.call(this, `/api/reportes/financieros/saldos/cliente/${c.id}`);
      contexto = `SALDO CLIENTE ${c.nombre}: ${JSON.stringify(saldo)}`;
    }
  } else if (saldoProveedor) {
    const nombre = saldoProveedor[1].trim();
    const provs = await get.call(this, '/api/proveedores/simple');
    const p = findByName(provs, nombre);
    if (!p) {
      contexto = `No encontré proveedor "${nombre}" en el sistema.`;
    } else {
      const saldo = await get.call(this, `/api/reportes/financieros/saldos/proveedor/${p.id}`);
      contexto = `SALDO PROVEEDOR ${p.nombre}: ${JSON.stringify(saldo)}`;
    }
  } else if (ccObra) {
    const nombre = ccObra[1].trim();
    const obras = await get.call(this, '/api/obras');
    const o = findByName(obras, nombre);
    if (!o) {
      contexto = `No encontré obra "${nombre}" en el sistema.`;
    } else {
      const cc = await get.call(this, `/api/reportes/cuenta-corriente/obra/${o.id}`);
      contexto = `CUENTA CORRIENTE OBRA ${o.nombre}: ${JSON.stringify(cc)}`;
    }
  } else if (msg.includes('resumen') || msg.includes('dashboard') || msg.includes('estado general') || msg.includes('ayuda') || msg.includes('hola')) {
    const data = await get.call(this, '/api/reportes/generales/resumen');
    contexto = `RESUMEN FINANCIERO SGO: ${JSON.stringify(data)}`;
  } else if (msg.includes('flujo') || msg.includes('caja')) {
    const data = await get.call(this, '/api/flujo-caja/principal');
    contexto = `FLUJO DE CAJA: ${JSON.stringify(data)}`;
  } else if (msg.includes('movimiento') || msg.includes('transacci')) {
    const data = await get.call(this, '/api/transacciones/recientes');
    contexto = `MOVIMIENTOS RECIENTES: ${JSON.stringify(data)}`;
  } else if (msg.includes('obra')) {
    const data = await get.call(this, '/api/obras');
    contexto = `OBRAS DEL SISTEMA: ${JSON.stringify(data)}`;
  } else if (msg.includes('cliente')) {
    const data = await get.call(this, '/api/clientes');
    contexto = `CLIENTES DEL SISTEMA: ${JSON.stringify(data)}`;
  } else if (msg.includes('proveedor')) {
    const data = await get.call(this, '/api/proveedores/simple');
    contexto = `PROVEEDORES DEL SISTEMA: ${JSON.stringify(data)}`;
  } else {
    contexto = '';
  }
} catch(e) {
  contexto = `Error al consultar datos: ${e.message}`;
}

return [{ json: { from, userMessage, contexto } }];

const from = $('Obtener Datos SGO').first().json.from;
const text = ($input.first().json.text || '').trim();

if (!from || !text) return [];

// Argentina: Meta envía 5493XXXXXXXX pero sandbox acepta 543XXXXXXXX (sin el 9 móvil)
const toNormalized = from.startsWith('549') ? '54' + from.slice(3) : from;

const waBody = {
  messaging_product: 'whatsapp',
  recipient_type: 'individual',
  to: toNormalized,
  type: 'text',
  text: { body: text.length > 3500 ? text.substring(0, 3500) + '...' : text, preview_url: false }
};

return [{ json: waBody }];
